solution_code:
#include <iostream>
#include <string>

struct Employee
{
    std::string name;
    int id;
};

void printEmployee(const Employee* e)
{
    std::cout << "Found: " << e->name << " (ID: " << e->id << ")\n";
}

int main()
{
    int n{};
    int queryId{};
    std::cin >> n >> queryId;

    Employee found{};
    Employee* match{ nullptr };

    for (int i{ 0 }; i < n; ++i)
    {
        std::string name;
        int id{};
        std::cin >> name >> id;
        if (id == queryId)
        {
            found = Employee{ name, id };
            match = &found;
        }
    }

    if (match != nullptr)
        printEmployee(match);
    else
        std::cout << "Not found\n";

    return 0;
}

