solution_code:
#include <iostream>

struct Rect
{
    int width;
    int height;
};

void doubleSize(Rect* r)
{
    r->width *= 2;
    r->height *= 2;
}

void printRect(const Rect& r)
{
    std::cout << r.width << " x " << r.height
              << " (area: " << r.width * r.height << ")\n";
}

int main()
{
    int w{}, h{};
    std::cin >> w >> h;

    Rect rect{ w, h };

    std::cout << "Before: ";
    printRect(rect);

    doubleSize(&rect);

    std::cout << "After: ";
    printRect(rect);

    return 0;
}
